useForm({
defaultValues: {firstName: '', lastName: '', emailAddress: ''},
validators: {
onSubmitAsync: async ({value: data, signal}) => {
const response = await fetch('/api/users', {
method: 'POST',
headers: {'Content-Type': 'application/json'},
body: JSON.stringify(data),
signal: signal, // ✅ AbortSignal available
})
if (response.ok) {
console.log(await response.json()) // "on success" handling here if you need access to the response body
} else {
// Must be an error map matching the shape of your form data
// e.g. { firstName: 'Required', emailAddress: 'Must be valid email' }
return await response.json()
}
},
},
onSubmit: () => {
// consider this an optional "on success" hook
},
})
